var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......늦었군.","JPN":"……遅かったな。","ENG":"You're late.","TWN":"……你們太慢了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장! 살아 있었구나?!","JPN":"隊長！　生きてたんだね！！","ENG":"Captain! You're alive!","TWN":"隊長！你還活著呀？！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그러게 말했잖아. 우리도 살아 나왔는데 저 인간이 쉽게 죽을 리 없지.","JPN":"言っただろ。俺たちだって生き残ったのに、あの人がそう簡単に死ぬわけがない。","ENG":"I told you. If we made it out, there's no way he'd croak so easily.","TWN":"我就說吧，我們都逃出來了，他怎麼可能會那麼輕易死掉。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"다친 데는 어때.","JPN":"ケガの具合はどうだ？","ENG":"You okay?","TWN":"傷口怎麼樣？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"총알 몇 발 스친 정도야. 다행히 몸에 박힌 놈은 없는 거 같다.","JPN":"何発かかすった程度だ。幸い、貫通していない。","ENG":"Had a few bullets graze me. Fortunately none of them ended up inside me, I think.","TWN":"被子彈劃傷了幾處，沒有直接命中。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"괜찮은 거 맞아? 옷이 피투성인데?","JPN":"本当に大丈夫？　服が血まみれなんだけど。","ENG":"You sure you're okay? You're covered in blood!","TWN":"真的沒事嗎？你身上到處都是血痕。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"병원이라도 가봐야 하는 거 아냐?","JPN":"病院に行ったほうがいいんじゃない？","ENG":"Maybe you should go to the hospital.","TWN":"要不要去醫院看看？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"너 돌았냐? 우리 같은 놈들이 갈 병원이 어디 있어?","JPN":"お前、頭大丈夫か？　俺らみたいな人を受け入れてくれる病院がどこにあるんだよ。","ENG":"You serious? We can't go to the hospital.","TWN":"妳瘋了嗎？我們這種身份怎麼可能去醫院？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아마 정문 넘어가자마자 경찰들에게 잡혀갈 텐데.","JPN":"入った途端に警察に連行されるだけだろ。","ENG":"The cops will cuff him right at the entrance.","TWN":"馬上會被員警們抓到的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그래도......","JPN":"でも……","ENG":"Still...","TWN":"就算這樣……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지훈이 말이 맞아. 그리고 너무 걱정 마라.","JPN":"ゴトウの言うとおりだ。あと、そんなに心配する必要はない。","ENG":"Jihoon's right. And don't worry.","TWN":"智勳說的對，妳也不用太擔心。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이 정도는 파스나 좀 바르면 나으니까.","JPN":"この程度の傷は塗り薬で治る。","ENG":"I can just put a bandage on it. It should heal right up.","TWN":"這點小傷只要擦點藥就可以了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"내, 내가 발라 줄게.","JPN":"わ、私が塗ってあげる。","ENG":"L-let me help you with that.","TWN":"我、我來幫你吧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"하이고, 여기가 네놈들 동창회 장소라도 되는 줄 아냐?","JPN":"まったく、ここをお前さんたちの憩い場と勘違いしてるんじゃないか？","ENG":"Come on, kids. This ain't some diner for your happy little reunion.","TWN":"哎喲，你們是在這裡開校友會嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"다 큰 놈들이 뭐 좋은 일로 왔다고 떠들어, 떠들긴.","JPN":"いい歳して祝い事でもないのに、そんなに賑やかにしやがって。","ENG":"Keep down the chatter, would ya? You're acting like a bunch of children.","TWN":"有什麼好事啊，這麼熱鬧。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"간판 안 보여? 여기 총포상이야, 총포상.","JPN":"看板が見えないのかい？　ここは銃砲屋だぞ、銃砲屋。","ENG":"Don't you see that sign? This place is a gun shop.","TWN":"沒看到招牌嗎？這裡是軍火店。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"카페에서 떠들려면 커피를 사고, 총포상에서 떠들려면 총을 사야 할 거 아냐.","JPN":"カフェでおしゃべりするならコーヒーを買え。銃砲屋でおしゃべりするなら銃を買え。","ENG":"Save your chitchat for a cafe or something. You ought to buy guns at a gun shop.","TWN":"想在咖啡店聊天就要點杯咖啡，想在軍火店聊天就必須買幾把槍。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"거 참 까탈스럽네, 영감.","JPN":"まあまあ、そんな冷たいこと言わないでくれよ、ジジイ。","ENG":"Don't be so grumpy.","TWN":"你可真苛刻，老頭。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};